UPDATE spots SET lat = 35.75985, lng = 139.43946000000003, updated_at = 1783690587446 WHERE slug = 'tamako-cycling-road';
UPDATE spots SET is_published = 1, description = '武蔵大和駅そばを起点に多摩湖(村山貯水池)の湖畔を一周する約11.8kmのコースです。大部分が自転車歩行者専用道のため車を気にせず走ることができ、湖と森の景色の変化を楽しみながら距離を踏めます。起伏はわずかで安定したペース走にも好適。途中にトイレや自動販売機があり、補給ポイントを確認しながら走れば安心です。', access = '西武多摩湖線 武蔵大和駅から徒歩すぐ。狭山公園経由で湖畔に出られます。' WHERE slug = 'tamako-cycling-road';
INSERT INTO spots (id, slug, name, name_kana, prefecture, city, lat, lng, description, access, has_toilet, has_water_fountain, has_vending_machine, has_locker, has_shower, has_sento_nearby, has_parking, has_convenience_store, night_lighting, track_usage, is_published, created_at, updated_at) VALUES ('b054cbfc-b5da-4a1f-9734-c0f7e68ae55a', 'yakushima-loop', '屋久島1周', 'やくしまいっしゅう', '鹿児島県', '熊毛郡屋久島町', 30.390000000000004, 130.65216, '屋久島空港近くの小瀬田を起点に、県道77号・78号で屋久島をぐるりと一周する約97.6kmのコースです。東部の集落を抜け、南部の海岸線から世界自然遺産地域を貫く西部林道へ。原生林の中の1〜1.5車線路ではヤクシカやヤクシマザルに出会えます。獲得標高は約1300mで、永田から宮之浦にかけては海沿いのアップダウンが続きます。西部林道区間(栗生〜永田の約20km)には自販機・トイレが無いため、補給計画は入念に。ウルトラマラソンの練習や1泊2日の旅ランにも向く、島一周の大周回です。', '屋久島空港(小瀬田)そばが起点。宮之浦港・安房港からもコース上に合流できます。', 1, 0, 1, 0, 0, 0, 1, 0, 'dark', NULL, 1, 1783690587446, 1783690587446);
